import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for try/catch indentation and typealias indentation issues.
 * See: https://github.com/pinterest/ktlint/issues/1935
 */
class IndentationRuleTryCatchTypealiasTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Nested
    inner class `Given try-catch on separate lines` {
        @Test
        fun `Given a function expression with try-catch where catch is on a new line`() {
            val code =
                """
                fun test() = try {
                    1
                }
                catch(_: Throwable) {
                    2
                }
                """.trimIndent()
            val formattedCode =
                """
                fun test() = try {
                    1
                }
                catch(_: Throwable) {
                    2
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a function expression with try-catch-finally where all parts are on separate lines`() {
            val code =
                """
                fun test() = try {
                    1
                }
                catch(_: Throwable) {
                    2
                }
                finally {
                    println("done")
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a val expression with try-catch where catch is on a new line`() {
            val code =
                """
                val x = try {
                    1
                }
                catch(_: Throwable) {
                    2
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a try-catch with indent size 2`() {
            val code =
                """
                fun test() = try {
                  1
                }
                catch(_: Throwable) {
                  2
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY to 2)
                .hasNoLintViolations()
        }

        @Test
        fun `Given try-catch with multiple catch blocks on separate lines`() {
            val code =
                """
                fun test() = try {
                    doSomething()
                }
                catch(_: IllegalArgumentException) {
                    handleIllegalArgument()
                }
                catch(_: IllegalStateException) {
                    handleIllegalState()
                }
                catch(_: Throwable) {
                    handleOther()
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given typealias with type on next line` {
        @Test
        fun `Given a typealias with type reference on the next line`() {
            val code =
                """
                typealias Foo =
                    HashMap<Bar, Baz?>
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a typealias with type reference on the next line and indent size 2`() {
            val code =
                """
                typealias Foo =
                  HashMap<Bar, Baz?>
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY to 2)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a typealias with missing indentation should be fixed`() {
            val code =
                """
                typealias Foo =
                HashMap<Bar, Baz?>
                """.trimIndent()
            val formattedCode =
                """
                typealias Foo =
                    HashMap<Bar, Baz?>
                """.trimIndent()
            indentationRuleAssertThat(code)
                .hasLintViolation(2, 1, "Unexpected indentation (0) (should be 4)")
                .isFormattedAs(formattedCode)
        }
    }
}
"}

